public class ProductController : Controller {
    [HttpGet]
    public IActionResult Index() => View();

    // GET /product/reviews/ProductID
    [HttpGet("product/{id}/reviews")] 
    public IActionResult Reviews(int id)
        return View(new Product() { 
            Reviews = Review.Query().Where(review => review.Product == id).ToList() 
        });
}
    
// model 
public class Review {
    public int ID;
    public int UserID; // foreign key
    public int Product; // foreign key
    public DateTime Date;
    public string Title;
    public string Content;

    // static methods for database access 
    public static List<Review> Query() => new List<Review>();
}
        
public class Product {
    public int ID;
    public string Name;
    
    public List<Review> Reviews = new List<Review>(); 
        
    public static List<Product> Query() => new List<Product>(); // will return a list of all products
}